import { auth } from "@clerk/nextjs/server";
import { NextResponse } from "next/server";
import { createGitHubService } from "@/services/github.service";

/**
 * GET /api/github/repos
 * Fetch user's GitHub repositories
 */
export async function GET(request: Request) {
  try {
    // Authenticate user
    const { userId } = await auth();

    if (!userId) {
      return NextResponse.json(
        { error: "Unauthorized" },
        { status: 401 }
      );
    }

    // Get GitHub token from query params or headers
    // In production, this should be stored securely in the database
    const { searchParams } = new URL(request.url);
    const token = searchParams.get("token") || request.headers.get("x-github-token");

    if (!token) {
      return NextResponse.json(
        { error: "GitHub token is required" },
        { status: 400 }
      );
    }

    // Create GitHub service
    const githubService = createGitHubService(token);

    // Parse query parameters
    const sort = searchParams.get("sort") as "created" | "updated" | "pushed" | "full_name" | null;
    const direction = searchParams.get("direction") as "asc" | "desc" | null;
    const perPage = searchParams.get("per_page");
    const page = searchParams.get("page");

    // Fetch repositories
    const repositories = await githubService.getUserRepositories({
      sort: sort || "updated",
      direction: direction || "desc",
      per_page: perPage ? parseInt(perPage) : 30,
      page: page ? parseInt(page) : 1,
    });

    return NextResponse.json({
      repositories,
      count: repositories.length,
    });
  } catch (error) {
    console.error("Error fetching GitHub repositories:", error);

    return NextResponse.json(
      { 
        error: "Failed to fetch repositories",
        message: error instanceof Error ? error.message : "Unknown error"
      },
      { status: 500 }
    );
  }
}

